    /**
     * Helper method to check if two classes are primitive-wrapper equivalents
     * (e.g., int and Integer, boolean and Boolean, etc.)
     *
     * @param cls1 First class to check
     * @param cls2 Second class to check
     * @return true if cls1 and cls2 are primitive-wrapper equivalents
     */
    protected boolean _isPrimitiveAndWrapperEquivalent(Class<?> cls1, Class<?> cls2) {
        if (cls1 == cls2) {
            return true;
        }
        if (cls1.isPrimitive() && cls2.isPrimitive()) {
            return cls1 == cls2;
        }
        if (!cls1.isPrimitive() && !cls2.isPrimitive()) {
            return cls1 == cls2;
        }

        // One is primitive, one is wrapper - check if they're a matched pair
        if (cls1.isPrimitive()) {
            // cls1 is primitive, cls2 should be its wrapper
            if (cls1 == int.class) return cls2 == Integer.class;
            if (cls1 == long.class) return cls2 == Long.class;
            if (cls1 == boolean.class) return cls2 == Boolean.class;
            if (cls1 == double.class) return cls2 == Double.class;
            if (cls1 == float.class) return cls2 == Float.class;
            if (cls1 == byte.class) return cls2 == Byte.class;
            if (cls1 == char.class) return cls2 == Character.class;
            if (cls1 == short.class) return cls2 == Short.class;
            if (cls1 == void.class) return cls2 == Void.class;
        } else {
            // cls2 is primitive, cls1 should be its wrapper
            if (cls2 == int.class) return cls1 == Integer.class;
            if (cls2 == long.class) return cls1 == Long.class;
            if (cls2 == boolean.class) return cls1 == Boolean.class;
            if (cls2 == double.class) return cls1 == Double.class;
            if (cls2 == float.class) return cls1 == Float.class;
            if (cls2 == byte.class) return cls1 == Byte.class;
            if (cls2 == char.class) return cls1 == Character.class;
            if (cls2 == short.class) return cls1 == Short.class;
            if (cls2 == void.class) return cls1 == Void.class;
        }
        return false;
    }


}

