+    protected boolean _isPrimitiveAndWrapperEquivalent(Class<?> cls1, Class<?> cls2) {
+        if (cls1 == cls2) {
+            return true;
+        }
+        if (cls1.isPrimitive() && cls2.isPrimitive()) {
+            return cls1 == cls2;
+        }
+        if (!cls1.isPrimitive() && !cls2.isPrimitive()) {
+            return cls1 == cls2;
+        }
